// GENERATED by `idealyst run ios --aas`. Splash values are
// substituted from `[package.metadata.idealyst.app.splash]` at build
// time. After the splash dismisses (or immediately if duration_ms == 0),
// `ios_main(view, endpoint)` connects to the dev-server at the URL
// the CLI baked into Info.plist as `IdealystDevEndpoint`.
//
// The endpoint is set by `idealyst dev` based on (a) the dev-server's
// actual bound port (read from its port-file sentinel) and (b) the
// host's LAN IP (for device builds) or `localhost`/`10.0.2.2` (for
// simulator / emulator). Rebuilding via `idealyst dev` is the only
// way to change which dev-server this build connects to.

import UIKit

/// Resolves the dev-server URL the wrapper should connect to. Lives
/// in Info.plist so device builds don't need a fresh Rust compile
/// to change which host they target — `plutil -replace
/// IdealystDevEndpoint -string ws://…` and reinstall.
private func resolveEndpoint() -> String {
    if let s = Bundle.main.object(forInfoDictionaryKey: "IdealystDevEndpoint") as? String,
       !s.isEmpty
    {
        return s
    }
    // Empty fallback — the CLI always writes this key. Reaching here
    // means the build wasn't done through `idealyst dev`; ios_main
    // bails with a clear error message rather than connecting to
    // nothing.
    return ""
}

class ViewController: UIViewController {
    override func viewDidLoad() {
        super.viewDidLoad()

        let splashDurationMs: Int = {{SPLASH_DURATION_MS}}
        if splashDurationMs == 0 {
            view.backgroundColor = .white
            mountRuntimeServerClient()
        } else {
            showSplashThenMount(durationMs: splashDurationMs)
        }
    }

    deinit {
        ios_teardown()
    }

    private func mountRuntimeServerClient() {
        let rootPtr = Unmanaged.passUnretained(view).toOpaque()
        let endpoint = resolveEndpoint()
        endpoint.withCString { cstr in
            ios_main(rootPtr, cstr)
        }
    }

    private func showSplashThenMount(durationMs: Int) {
        view.backgroundColor = UIColor(hexString: "{{SPLASH_BG}}")

        let title = UILabel()
        title.text = "{{SPLASH_TITLE}}"
        title.textAlignment = .center
        title.textColor = UIColor(hexString: "{{SPLASH_TITLE_COLOR}}")
        title.font = .systemFont(ofSize: 36, weight: .bold)
        title.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(title)
        NSLayoutConstraint.activate([
            title.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            title.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            title.leadingAnchor.constraint(greaterThanOrEqualTo: view.leadingAnchor, constant: 24),
            title.trailingAnchor.constraint(lessThanOrEqualTo: view.trailingAnchor, constant: -24),
        ])

        let delay = TimeInterval(durationMs) / 1000.0
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            guard let self = self else { return }
            UIView.animate(withDuration: 0.25, animations: {
                title.alpha = 0
                self.view.backgroundColor = .white
            }, completion: { _ in
                title.removeFromSuperview()
                self.mountRuntimeServerClient()
            })
        }
    }
}

private extension UIColor {
    /// Parse "#RRGGBB" or "RRGGBB" into a UIColor. Falls back to
    /// magenta on parse errors so problems are visually obvious.
    convenience init(hexString: String) {
        let trimmed = hexString
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "#", with: "")
        var rgb: UInt64 = 0
        guard Scanner(string: trimmed).scanHexInt64(&rgb), trimmed.count == 6 else {
            self.init(red: 1, green: 0, blue: 1, alpha: 1)
            return
        }
        let r = CGFloat((rgb & 0xFF0000) >> 16) / 255
        let g = CGFloat((rgb & 0x00FF00) >> 8) / 255
        let b = CGFloat(rgb & 0x0000FF) / 255
        self.init(red: r, green: g, blue: b, alpha: 1.0)
    }
}
